import secrets
import hashlib
from datetime import datetime, timedelta
from typing import Optional, Dict
from functools import wraps
from flask import Flask, request, jsonify

app = Flask(__name__)

users_db = {
    "admin": hashlib.sha256("password123".encode()).hexdigest(),
    "user1": hashlib.sha256("mypassword".encode()).hexdigest()
}

tokens_db: Dict[str, Dict] = {}

TOKEN_EXPIRY_HOURS = 24


def generate_token() -> str:
    return secrets.token_urlsafe(32)


def create_token(username: str) -> str:
    token = generate_token()
    tokens_db[token] = {
        "username": username,
        "created_at": datetime.now(),
        "expires_at": datetime.now() + timedelta(hours=TOKEN_EXPIRY_HOURS)
    }
    return token


def verify_token(token: str) -> Optional[str]:
    if token not in tokens_db:
        return None
    
    token_data = tokens_db[token]
    if datetime.now() > token_data["expires_at"]:
        del tokens_db[token]
        return None
    
    return token_data["username"]


def token_required(f):
    @wraps(f)
    def decorated_function(*args, **kwargs):
        token = request.headers.get("Authorization")
        
        if not token:
            return jsonify({"error": "Token is missing"}), 401
        
        if token.startswith("Bearer "):
            token = token[7:]
        
        username = verify_token(token)
        if not username:
            return jsonify({"error": "Invalid or expired token"}), 401
        
        request.current_user = username
        return f(*args, **kwargs)
    
    return decorated_function


@app.route("/login", methods=["POST"])
def login():
    data = request.get_json()
    
    if not data or "username" not in data or "password" not in data:
        return jsonify({"error": "Username and password required"}), 400
    
    username = data["username"]
    password = data["password"]
    
    password_hash = hashlib.sha256(password.encode()).hexdigest()
    
    if username not in users_db or users_db[username] != password_hash:
        return jsonify({"error": "Invalid credentials"}), 401
    
    token = create_token(username)
    
    return jsonify({
        "message": "Login successful",
        "token": token,
        "expires_in_hours": TOKEN_EXPIRY_HOURS
    }), 200


@app.route("/logout", methods=["POST"])
@token_required
def logout():
    token = request.headers.get("Authorization")
    if token.startswith("Bearer "):
        token = token[7:]
    
    if token in tokens_db:
        del tokens_db[token]
    
    return jsonify({"message": "Logout successful"}), 200


@app.route("/protected", methods=["GET"])
@token_required
def protected_route():
    return jsonify({
        "message": "Access granted to protected resource",
        "user": request.current_user
    }), 200


@app.route("/profile", methods=["GET"])
@token_required
def get_profile():
    return jsonify({
        "username": request.current_user,
        "message": "This is your profile data"
    }), 200


@app.route("/public", methods=["GET"])
def public_route():
    return jsonify({"message": "This is a public endpoint"}), 200


if __name__ == "__main__":
    app.run(debug=True, port=5000)